  1→import { useState, useRef, useCallback, useMemo, useEffect } from 'react';
  2→import { userHomeCoords, MAX_UNIVERSE_ZOOM, MIN_UNIVERSE_ZOOM } from '../utils/starUtils';
  3→
  4→const useUniverseCamera = (userId, hasOwnPosts) => {
  5→    const stageRef = useRef(null);
  6→    const dragStartRef = useRef(null);
  7→    const lastPinchDist = useRef(null);
  8→    const isPinching = useRef(false);
  9→    const hasAdjustedZoom = useRef(false);
 10→
 11→    // Flight state
 12→    const isFlying = useRef(false);
 13→    const flyAnimRef = useRef(null);
 14→    const cameraRef = useRef(null);
 15→    const zoomRef = useRef(null);
 16→
 17→    const [stageSize, setStageSize] = useState({
 18→        width: window.innerWidth,
 19→        height: window.innerHeight,
 20→    });
 21→
 22→    const initialCamera = useMemo(() => {
 23→        if (!userId) return { x: 0, y: 0 };
 24→        return userHomeCoords(userId);
 25→    }, [userId]);
 26→
 27→    // Always enter Universe at maximum zoom-out.
 28→    const initialZoom = useMemo(() => MIN_UNIVERSE_ZOOM, []);
 29→
 30→    const [camera, setCamera] = useState(initialCamera);
 31→    const [zoom, setZoom] = useState(initialZoom);
 32→    const [isDragging, setIsDragging] = useState(false);
 33→
 34→    // Keep refs in sync with state so flyTo reads fresh values without deps
 35→    cameraRef.current = camera;
 36→    zoomRef.current = zoom;
 37→
 38→    // If logged-in user has no posts, center camera while keeping max zoom-out.
 39→    useEffect(() => {
 40→        if (hasAdjustedZoom.current) return;
 41→        if (hasOwnPosts === null) return; // still loading
 42→        if (!userId) return;
 43→        if (!hasOwnPosts) {
 44→            hasAdjustedZoom.current = true;
 45→            setCamera({ x: 0, y: 0 });
 46→            setZoom(MIN_UNIVERSE_ZOOM);
 47→        } else {
 48→            hasAdjustedZoom.current = true;
 49→        }
 50→    }, [hasOwnPosts, userId]);
 51→
 52→    // Resize
 53→    useEffect(() => {
 54→        const onResize = () => setStageSize({ width: window.innerWidth, height: window.innerHeight });
 55→        window.addEventListener('resize', onResize);
 56→        return () => window.removeEventListener('resize', onResize);
 57→    }, []);
 58→
 59→    // Cleanup flight on unmount
 60→    useEffect(() => {
 61→        return () => {
 62→            if (flyAnimRef.current) {
 63→                cancelAnimationFrame(flyAnimRef.current);
 64→                flyAnimRef.current = null;
 65→            }
 66→            isFlying.current = false;
 67→        };
 68→    }, []);
 69→
 70→    // Center world coords (for display)
 71→    const centerWorld = useMemo(() => ({
 72→        x: Math.round(camera.x),
 73→        y: Math.round(camera.y),
 74→    }), [camera]);
 75→
 76→    // Layer transform helper
 77→    const getLayerProps = useCallback((parallaxFactor) => ({
 78→        x: stageSize.width / 2 - camera.x * parallaxFactor * zoom,
 79→        y: stageSize.height / 2 - camera.y * parallaxFactor * zoom,
 80→        scaleX: zoom,
 81→        scaleY: zoom,
 82→    }), [camera, zoom, stageSize]);
 83→
 84→    // Viewport bounds at parallax 1.0 (for data fetching)
 85→    const getViewportBounds = useCallback(() => {
 86→        const halfW = (stageSize.width / 2) / zoom;
 87→        const halfH = (stageSize.height / 2) / zoom;
 88→        const pad = 200 / zoom;
 89→        return {
 90→            minX: camera.x - halfW - pad,
 91→            maxX: camera.x + halfW + pad,
 92→            minY: camera.y - halfH - pad,
 93→            maxY: camera.y + halfH + pad,
 94→        };
 95→    }, [camera, zoom, stageSize]);
 96→
 97→    // --- Drag handling (Stage is NOT draggable) ---
 98→    const handleMouseDown = useCallback((e) => {
 99→        if (isFlying.current) return;
100→        // Only left button for mouse
101→        if (e.evt.button !== undefined && e.evt.button !== 0) return;
102→        dragStartRef.current = {
103→            pointerX: e.evt.clientX ?? e.evt.touches?.[0]?.clientX,
104→            pointerY: e.evt.clientY ?? e.evt.touches?.[0]?.clientY,
105→            camX: camera.x,
106→            camY: camera.y,
107→        };
108→        setIsDragging(true);
109→    }, [camera]);
110→
111→    const handleMouseMove = useCallback((e) => {
112→        if (!dragStartRef.current) return;
113→        if (isPinching.current) return;
114→        const px = e.evt.clientX ?? e.evt.touches?.[0]?.clientX;
115→        const py = e.evt.clientY ?? e.evt.touches?.[0]?.clientY;
116→        if (px == null || py == null) return;
117→        const dx = (px - dragStartRef.current.pointerX) / zoom;
118→        const dy = (py - dragStartRef.current.pointerY) / zoom;
119→        setCamera({
120→            x: dragStartRef.current.camX - dx,
121→            y: dragStartRef.current.camY - dy,
122→        });
123→    }, [zoom]);
124→
125→    const handleMouseUp = useCallback(() => {
126→        dragStartRef.current = null;
127→        setIsDragging(false);
128→        isPinching.current = false;
129→        lastPinchDist.current = null;
130→    }, []);
131→
132→    // --- Wheel zoom ---
133→    const handleWheel = useCallback((e) => {
134→        e.evt.preventDefault();
135→        if (isFlying.current) return;
136→
137→        const stage = stageRef.current;
138→        if (!stage) return;
139→
140→        const pointer = stage.getPointerPosition();
141→        if (!pointer) return;
142→
143→        const screenCenterX = stageSize.width / 2;
144→        const screenCenterY = stageSize.height / 2;
145→
146→        const scaleBy = 1.08;
147→        const direction = e.evt.deltaY > 0 ? -1 : 1;
148→        const oldZoom = zoom;
149→        const newZoom = Math.min(Math.max(
150→            direction > 0 ? oldZoom * scaleBy : oldZoom / scaleBy,
151→            MIN_UNIVERSE_ZOOM
152→        ), MAX_UNIVERSE_ZOOM);
153→
154→        // World point under cursor before zoom
155→        const worldX = camera.x + (pointer.x - screenCenterX) / oldZoom;
156→        const worldY = camera.y + (pointer.y - screenCenterY) / oldZoom;
157→
158→        // Adjust camera so same world point stays under cursor
159→        setCamera({
160→            x: worldX - (pointer.x - screenCenterX) / newZoom,
161→            y: worldY - (pointer.y - screenCenterY) / newZoom,
162→        });
163→        setZoom(newZoom);
164→    }, [zoom, camera, stageSize]);
165→
166→    // --- Touch / Pinch ---
167→    const handleTouchMove = useCallback((e) => {
168→        if (isFlying.current) return;
169→
170→        const touch = e.evt;
171→        if (touch.touches.length === 2) {
172→            // Pinch zoom
173→            isPinching.current = true;
174→            touch.preventDefault();
175→
176→            const t1 = touch.touches[0];
177→            const t2 = touch.touches[1];
178→            const dist = Math.hypot(t2.clientX - t1.clientX, t2.clientY - t1.clientY);
179→
180→            if (lastPinchDist.current === null) {
181→                lastPinchDist.current = dist;
182→                return;
183→            }
184→
185→            const oldZoom = zoom;
186→            const newZoom = Math.min(
187→                Math.max(oldZoom * (dist / lastPinchDist.current), MIN_UNIVERSE_ZOOM),
188→                MAX_UNIVERSE_ZOOM
189→            );
190→            lastPinchDist.current = dist;
191→
192→            const centerX = (t1.clientX + t2.clientX) / 2;
193→            const centerY = (t1.clientY + t2.clientY) / 2;
194→            const screenCenterX = stageSize.width / 2;
195→            const screenCenterY = stageSize.height / 2;
196→
197→            const worldX = camera.x + (centerX - screenCenterX) / oldZoom;
198→            const worldY = camera.y + (centerY - screenCenterY) / oldZoom;
199→
200→            setCamera({
201→                x: worldX - (centerX - screenCenterX) / newZoom,
202→                y: worldY - (centerY - screenCenterY) / newZoom,
203→            });
204→            setZoom(newZoom);
205→        } else if (touch.touches.length === 1 && !isPinching.current) {
206→            // Single finger drag — handled by mouseMove logic
207→            handleMouseMove(e);
208→        }
209→    }, [zoom, camera, stageSize, handleMouseMove]);
210→
211→    const handleTouchEnd = useCallback(() => {
212→        lastPinchDist.current = null;
213→        if (isPinching.current) {
214→            isPinching.current = false;
215→            dragStartRef.current = null;
216→        }
217→    }, []);
218→
219→    const stageEvents = useMemo(() => ({
220→        onMouseDown: handleMouseDown,
221→        onMouseMove: handleMouseMove,
222→        onMouseUp: handleMouseUp,
223→        onWheel: handleWheel,
224→        onTouchStart: handleMouseDown,
225→        onTouchMove: handleTouchMove,
226→        onTouchEnd: handleTouchEnd,
227→    }), [handleMouseDown, handleMouseMove, handleMouseUp, handleWheel, handleTouchMove, handleTouchEnd]);
228→
229→    const jumpTo = useCallback((targetX, targetY) => {
230→        if (flyAnimRef.current) {
231→            cancelAnimationFrame(flyAnimRef.current);
232→            flyAnimRef.current = null;
233→        }
234→        isFlying.current = false;
235→
236→        const nextX = Number.isFinite(targetX) ? targetX : cameraRef.current.x;
237→        const nextY = Number.isFinite(targetY) ? targetY : cameraRef.current.y;
238→        setCamera({ x: nextX, y: nextY });
239→    }, []);
240→
241→    // Google Maps-style fly-to: zoom out → pan → zoom in (parabolic arc)
242→    const flyTo = useCallback((targetX, targetY, targetZoom, onComplete) => {
243→        // Cancel any in-progress flight (without calling old onComplete)
244→        if (flyAnimRef.current) {
245→            cancelAnimationFrame(flyAnimRef.current);
246→            flyAnimRef.current = null;
247→        }
248→
249→        const startX = cameraRef.current.x;
250→        const startY = cameraRef.current.y;
251→        const startZoom = zoomRef.current;
252→        const resolvedTargetZoom = Number.isFinite(targetZoom) ? targetZoom : startZoom;
253→
254→        isFlying.current = true;
255→
256→        // Distance determines how far to zoom out
257→        const dist = Math.hypot(targetX - startX, targetY - startY);
258→
259→        // Fixed cinematic duration
260→        const duration = 1800;
261→
262→        // The "peak altitude" — zoom out proportional to travel distance
263→        const minZoom = Math.min(startZoom, resolvedTargetZoom);
264→        const peakZoomOut = Math.max(
265→            minZoom * 0.15,
266→            minZoom - dist * 0.00008
267→        );
268→        const midZoom = Math.max(MIN_UNIVERSE_ZOOM, Math.min(peakZoomOut, minZoom * 0.6));
269→
270→        const startTime = performance.now();
271→
272→        // Cubic ease-in-out
273→        const easeInOut = (t) => t < 0.5
274→            ? 4 * t * t * t
275→            : 1 - Math.pow(-2 * t + 2, 3) / 2;
276→
277→        const animate = (now) => {
278→            const elapsed = now - startTime;
279→            const raw = Math.min(elapsed / duration, 1);
280→            const t = easeInOut(raw);
281→
282→            // Pan linearly with the eased time
283→            const cx = startX + (targetX - startX) * t;
284→            const cy = startY + (targetY - startY) * t;
285→
286→            // Parabolic zoom: start → midZoom at t=0.5 → targetZoom at t=1
287→            const a = 2 * startZoom - 4 * midZoom + 2 * resolvedTargetZoom;
288→            const b = -3 * startZoom + 4 * midZoom - resolvedTargetZoom;
289→            const c = startZoom;
290→            const z = a * t * t + b * t + c;
291→
292→            setCamera({ x: cx, y: cy });
293→            const safeZ = Number.isFinite(z) ? z : startZoom;
294→            setZoom(Math.max(MIN_UNIVERSE_ZOOM, safeZ));
295→
296→            if (raw < 1) {
297→                flyAnimRef.current = requestAnimationFrame(animate);
298→            } else {
299→                flyAnimRef.current = null;
300→                isFlying.current = false;
301→                if (onComplete) onComplete();
302→            }
303→        };
304→
305→        flyAnimRef.current = requestAnimationFrame(animate);
306→    }, []); // stable — reads from refs
307→
