  1→/**
  2→ * Pure math functions for client-side gravity simulation.
  3→ * Zero DOM/React dependencies and worker-ready.
  4→ */
  5→
  6→const EPSILON = 1e-8;
  7→
  8→const clamp = (value, min, max) => Math.max(min, Math.min(max, value));
  9→
 10→const toFiniteNumber = (value) => {
 11→    const n = typeof value === 'number' ? value : Number(value);
 12→    return Number.isFinite(n) ? n : null;
 13→};
 14→
 15→const normalizeMaxEdges = (value, fallback) => {
 16→    const n = Math.floor(Number(value));
 17→    return Number.isFinite(n) && n > 0 ? n : fallback;
 18→};
 19→
 20→export const toEmbeddingArray = (value) => {
 21→    if (value == null) return null;
 22→
 23→    let source = null;
 24→
 25→    if (Array.isArray(value)) {
 26→        source = value;
 27→    } else if (ArrayBuffer.isView(value)) {
 28→        source = Array.from(value);
 29→    } else if (typeof value === 'string') {
 30→        const trimmed = value.trim();
 31→        if (!trimmed) return null;
 32→
 33→        if (trimmed.startsWith('[')) {
 34→            try {
 35→                const parsed = JSON.parse(trimmed);
 36→                if (Array.isArray(parsed)) source = parsed;
 37→            } catch {
 38→                source = null;
 39→            }
 40→        }
 41→
 42→        if (!source) {
 43→            source = trimmed
 44→                .replace(/[[\]()]/g, '')
 45→                .split(',')
 46→                .map((part) => part.trim())
 47→                .filter(Boolean);
 48→        }
 49→    }
 50→
 51→    if (!source || source.length === 0) return null;
 52→
 53→    const numeric = new Array(source.length);
 54→    for (let i = 0; i < source.length; i++) {
 55→        const n = Number(source[i]);
 56→        if (!Number.isFinite(n)) return null;
 57→        numeric[i] = n;
 58→    }
 59→    return numeric;
 60→};
 61→
 62→export const normalizeEmbedding = (vector) => {
 63→    const arr = toEmbeddingArray(vector);
 64→    if (!arr || arr.length === 0) return null;
 65→
 66→    let normSq = 0;
 67→    for (let i = 0; i < arr.length; i++) {
 68→        normSq += arr[i] * arr[i];
 69→    }
 70→    if (normSq <= EPSILON) return null;
 71→
 72→    const invNorm = 1 / Math.sqrt(normSq);
 73→    const out = new Float32Array(arr.length);
 74→    for (let i = 0; i < arr.length; i++) {
 75→        out[i] = arr[i] * invNorm;
 76→    }
 77→    return out;
 78→};
 79→
 80→export const cosineSimilarity = (a, b) => {
 81→    const arrA = toEmbeddingArray(a);
 82→    const arrB = toEmbeddingArray(b);
 83→    if (!arrA || !arrB || arrA.length === 0 || arrA.length !== arrB.length) {
 84→        return 0;
 85→    }
 86→
 87→    let dot = 0;
 88→    let normA = 0;
 89→    let normB = 0;
 90→
 91→    for (let i = 0; i < arrA.length; i++) {
 92→        const va = arrA[i];
 93→        const vb = arrB[i];
 94→        if (!Number.isFinite(va) || !Number.isFinite(vb)) return 0;
 95→        dot += va * vb;
 96→        normA += va * va;
 97→        normB += vb * vb;
 98→    }
 99→
100→    if (normA <= EPSILON || normB <= EPSILON) return 0;
101→
102→    const sim = dot / Math.sqrt(normA * normB);
103→    if (!Number.isFinite(sim)) return 0;
104→    return clamp(sim, -1, 1);
105→};
106→
107→export const computeGalaxyCentroids = (posts = []) => {
108→    const sumByUser = new Map();
109→    const postCountByUser = new Map();
110→
111→    for (const post of posts) {
112→        const userId = post?.users?.id ?? post?.user_id;
113→        if (!userId) continue;
114→
115→        const embedding = toEmbeddingArray(post?.embeddings);
116→        if (!embedding) continue;
117→
118→        if (!sumByUser.has(userId)) {
119→            sumByUser.set(userId, new Float64Array(embedding.length));
120→            postCountByUser.set(userId, 0);
121→        }
122→
123→        const sum = sumByUser.get(userId);
124→        if (!sum || sum.length !== embedding.length) continue;
125→
126→        for (let i = 0; i < embedding.length; i++) {
127→            sum[i] += embedding[i];
128→        }
129→        postCountByUser.set(userId, (postCountByUser.get(userId) || 0) + 1);
130→    }
131→
132→    const centroidByUser = new Map();
133→    for (const [userId, sum] of sumByUser.entries()) {
134→        const count = postCountByUser.get(userId) || 0;
135→        if (count <= 0) continue;
136→
137→        const mean = new Array(sum.length);
138→        for (let i = 0; i < sum.length; i++) {
139→            mean[i] = sum[i] / count;
140→        }
141→
142→        const normalized = normalizeEmbedding(mean);
143→        if (normalized) centroidByUser.set(userId, normalized);
144→    }
145→
146→    return { centroidByUser, postCountByUser };
147→};
148→
149→export const computeSectorKey = (x, y, sectorSize = 2000) => {
150→    const fx = toFiniteNumber(x);
151→    const fy = toFiniteNumber(y);
152→    const size = Math.max(1, Number(sectorSize) || 2000);
153→    if (fx == null || fy == null) return null;
154→
155→    const sx = Math.floor(fx / size);
156→    const sy = Math.floor(fy / size);
157→    return `${sx}:${sy}`;
158→};
159→
160→export const getNeighborSectorKeys = (centerKey) => {
161→    if (typeof centerKey !== 'string') return [];
162→    const [sxRaw, syRaw] = centerKey.split(':');
163→    const sx = Number(sxRaw);
164→    const sy = Number(syRaw);
165→    if (!Number.isFinite(sx) || !Number.isFinite(sy)) return [];
166→
167→    const keys = [];
168→    for (let dy = -1; dy <= 1; dy++) {
169→        for (let dx = -1; dx <= 1; dx++) {
170→            keys.push(`${sx + dx}:${sy + dy}`);
171→        }
172→    }
173→    return keys;
174→};
175→
176→export const buildSectorIndex = (items, getCoords, sectorSize = 2000) => {
177→    const index = new Map();
178→    if (!Array.isArray(items) || typeof getCoords !== 'function') return index;
179→
180→    for (const item of items) {
181→        const coords = getCoords(item);
182→        if (!coords) continue;
183→        const key = computeSectorKey(coords.x, coords.y, sectorSize);
184→        if (!key) continue;
185→
186→        if (!index.has(key)) index.set(key, []);
187→        index.get(key).push(item);
188→    }
189→
190→    return index;
191→};
192→
193→export const computeGalaxySimilarityEdges = (
194→    centroidByUser,
195→    activeUserIds,
196→    threshold = 0.3,
197→    maxEdges = 500
198→) => {
199→    if (!(centroidByUser instanceof Map) || centroidByUser.size < 2) return [];
200→
201→    const users = activeUserIds
202→        ? Array.from(activeUserIds).filter((id) => centroidByUser.has(id))
203→        : Array.from(centroidByUser.keys());
204→
205→    if (users.length < 2) return [];
206→
207→    const minSimilarity = Number.isFinite(Number(threshold)) ? Number(threshold) : 0.3;
208→    const edges = [];
209→
210→    for (let i = 0; i < users.length; i++) {
211→        for (let j = i + 1; j < users.length; j++) {
212→            const userA = users[i];
213→            const userB = users[j];
214→            const sim = cosineSimilarity(centroidByUser.get(userA), centroidByUser.get(userB));
215→            if (sim >= minSimilarity) {
216→                edges.push({ user_a: userA, user_b: userB, similarity: sim });
217→            }
218→        }
219→    }
220→
221→    edges.sort((a, b) => b.similarity - a.similarity);
222→    const limit = normalizeMaxEdges(maxEdges, 500);
223→    return edges.length > limit ? edges.slice(0, limit) : edges;
224→};
225→
226→const clampOffsetMagnitude = (offset, maxOffset) => {
227→    const limit = Math.max(0, Number(maxOffset) || 0);
228→    if (limit === 0) return { dx: 0, dy: 0 };
229→
230→    const mag = Math.sqrt(offset.dx * offset.dx + offset.dy * offset.dy);
231→    if (mag <= limit || mag <= EPSILON) return offset;
232→
233→    return {
234→        dx: (offset.dx / mag) * limit,
235→        dy: (offset.dy / mag) * limit,
236→    };
237→};
238→
239→export const computeGalaxyForces = (positions, targets, edges, options = {}) => {
240→    const forces = new Map();
241→    if (!(positions instanceof Map) || positions.size === 0) return forces;
242→
243→    const springK = Number.isFinite(Number(options.springK)) ? Number(options.springK) : 0.06;
244→    const edgeStrength = Number.isFinite(Number(options.edgeStrength)) ? Number(options.edgeStrength) : 0.0004;
245→    const idealDistanceScale = Number.isFinite(Number(options.idealDistanceScale))
246→        ? Number(options.idealDistanceScale)
247→        : 3000;
248→    const repulsion = Number.isFinite(Number(options.repulsion)) ? Number(options.repulsion) : 3e6;
249→    const maxRepulsionDistance = Number.isFinite(Number(options.maxRepulsionDistance))
250→        ? Number(options.maxRepulsionDistance)
251→        : 10000;
252→
253→    const activeIds = options.activeIds
254→        ? new Set(Array.from(options.activeIds).filter((id) => positions.has(id)))
255→        : new Set(positions.keys());
256→    const ids = Array.from(activeIds);
257→    if (ids.length === 0) return forces;
258→
259→    for (const id of ids) {
260→        forces.set(id, { fx: 0, fy: 0 });
261→    }
262→
263→    // 1) Spring toward targets (used as fallback when server targets exist).
264→    if (targets instanceof Map && targets.size > 0) {
265→        for (const id of ids) {
266→            const pos = positions.get(id);
267→            const target = targets.get(id);
268→            if (!pos || !target) continue;
269→            const f = forces.get(id);
270→            f.fx += (target.x - pos.x) * springK;
271→            f.fy += (target.y - pos.y) * springK;
272→        }
273→    }
274→
275→    // 2) Similarity edges.
276→    if (Array.isArray(edges) && edges.length > 0) {
277→        for (const edge of edges) {
278→            const userA = edge?.user_a;
279→            const userB = edge?.user_b;
280→            if (!activeIds.has(userA) || !activeIds.has(userB)) continue;
281→
282→            const posA = positions.get(userA);
283→            const posB = positions.get(userB);
284→            if (!posA || !posB) continue;
285→
286→            const fA = forces.get(userA);
287→            const fB = forces.get(userB);
288→            if (!fA || !fB) continue;
289→
290→            const similarity = clamp(Number(edge?.similarity) || 0, -1, 1);
291→            const dx = posB.x - posA.x;
292→            const dy = posB.y - posA.y;
293→            const distSq = Math.max(dx * dx + dy * dy, 1);
294→            const dist = Math.sqrt(distSq);
295→            const idealDist = idealDistanceScale * (1 - Math.max(0, similarity));
296→            const strength = Math.max(0, similarity) * edgeStrength * (dist - idealDist);
297→            const fx = (dx / dist) * strength;
298→            const fy = (dy / dist) * strength;
299→
300→            fA.fx += fx;
301→            fA.fy += fy;
302→            fB.fx -= fx;
303→            fB.fy -= fy;
304→        }
305→    }
306→
307→    // 3) Pairwise repulsion.
308→    const maxRepulsionDistanceSq = maxRepulsionDistance * maxRepulsionDistance;
309→    for (let i = 0; i < ids.length; i++) {
310→        for (let j = i + 1; j < ids.length; j++) {
311→            const a = positions.get(ids[i]);
312→            const b = positions.get(ids[j]);
313→            if (!a || !b) continue;
314→
315→            const dx = b.x - a.x;
316→            const dy = b.y - a.y;
317→            const distSqRaw = dx * dx + dy * dy;
318→            if (!Number.isFinite(distSqRaw) || distSqRaw > maxRepulsionDistanceSq) continue;
319→
320→            const distSq = Math.max(distSqRaw, 1);
321→            const dist = Math.sqrt(distSq);
322→            const force = repulsion / distSq;
323→            const fx = (dx / dist) * force;
324→            const fy = (dy / dist) * force;
325→
326→            const fA = forces.get(ids[i]);
327→            const fB = forces.get(ids[j]);
328→            fA.fx -= fx;
329→            fA.fy -= fy;
330→            fB.fx += fx;
331→            fB.fy += fy;
332→        }
333→    }
334→
335→    return forces;
336→};
