 3→// Mulberry32 — fast seeded 32-bit PRNG
 4→export const mulberry32 = (seed) => {
 5→    let s = seed | 0;
 6→    return () => {
 7→        s = (s + 0x6D2B79F5) | 0;
 8→        let t = Math.imul(s ^ (s >>> 15), 1 | s);
 9→        t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
10→        return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
11→    };
12→};
